import{_ as a,a as o,b as t,c as r}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as l,c as d,a2 as n}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"Adicionar canal Google Drive","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/upload/google-drive.md","filePath":"pt-BR/upload/google-drive.md","lastUpdated":1781962217000}'),c={name:"pt-BR/upload/google-drive.md"};function s(h,e,p,u,m,g){return l(),d("div",null,[...e[0]||(e[0]=[n('<h1 id="adicionar-canal-google-drive" tabindex="-1">Adicionar canal Google Drive <a class="header-anchor" href="#adicionar-canal-google-drive" aria-label="Permalink to &quot;Adicionar canal Google Drive&quot;">​</a></h1><p>O canal Google Drive usa uma conta Google Drive como destino de armazenamento.</p><h2 id="o-que-preparar" tabindex="-1">O que preparar <a class="header-anchor" href="#o-que-preparar" aria-label="Permalink to &quot;O que preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Uso</th></tr></thead><tbody><tr><td>Conta Google</td><td>Gerenciar Drive e OAuth</td></tr><tr><td>Projeto Google Cloud</td><td>Criar OAuth Client</td></tr><tr><td>Client ID / Client Secret</td><td>Autorizar o ImgBed</td></tr><tr><td>Refresh Token</td><td>Manter acesso de longo prazo</td></tr><tr><td>Domínio ImgBed</td><td>Configurar callback OAuth</td></tr></tbody></table><h2 id="criar-oauth-client" tabindex="-1">Criar OAuth Client <a class="header-anchor" href="#criar-oauth-client" aria-label="Permalink to &quot;Criar OAuth Client&quot;">​</a></h2><p>No Google Cloud Console, crie um OAuth Client do tipo Web application.</p><p><img src="'+a+'" alt="Criar OAuth Client" loading="lazy"></p><p>Adicione esta URI como redirecionamento autorizado:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://seu-dominio/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+o+'" alt="Configurar URL OAuth" loading="lazy"></p><h2 id="preencher-no-imgbed" tabindex="-1">Preencher no ImgBed <a class="header-anchor" href="#preencher-no-imgbed" aria-label="Permalink to &quot;Preencher no ImgBed&quot;">​</a></h2><p>Em Configurações de upload, escolha <code>Google Drive</code> e informe Client ID e Client Secret.</p><p><img src="'+t+'" alt="Configuração Google Drive" loading="lazy"></p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nome do canal</td><td>Por exemplo <code>Google Drive Main</code></td></tr><tr><td>Client ID</td><td>OAuth Client ID</td></tr><tr><td>Client Secret</td><td>OAuth Client Secret</td></tr><tr><td>Refresh Token</td><td>Obtido depois</td></tr><tr><td>Diretório raiz</td><td>Opcional, normalmente <code>imgbed</code></td></tr></tbody></table><h2 id="obter-refresh-token" tabindex="-1">Obter Refresh Token <a class="header-anchor" href="#obter-refresh-token" aria-label="Permalink to &quot;Obter Refresh Token&quot;">​</a></h2><ol><li>No ImgBed, clique em <code>Obter Token</code>.</li><li>Entre com a conta Google que será o destino.</li><li>Aceite as permissões.</li><li>Copie o Refresh Token exibido na página de callback.</li><li>Cole no campo <code>Refresh Token</code>.</li></ol><p><img src="'+r+'" alt="Copiar Refresh Token" loading="lazy"></p><h2 id="verificacao" tabindex="-1">Verificação <a class="header-anchor" href="#verificacao" aria-label="Permalink to &quot;Verificação&quot;">​</a></h2><ol><li>Salve o canal.</li><li>Envie uma imagem de teste.</li><li>Confira se ela aparece no Google Drive.</li><li>Abra o link retornado pelo ImgBed.</li></ol><h2 id="observacoes" tabindex="-1">Observações <a class="header-anchor" href="#observacoes" aria-label="Permalink to &quot;Observações&quot;">​</a></h2><ul><li>Se a tela de consentimento OAuth não estiver pronta, a autorização pode falhar.</li><li>A conta que gera o Refresh Token será a conta de armazenamento.</li><li>Se o Drive não tiver espaço, o upload falhará.</li><li>Não publique o Client Secret.</li></ul>',21)])])}const v=i(c,[["render",s]]);export{C as __pageData,v as default};
